655	static void
656	ngx_cleanup_environment(void *data)
657	{
658	    char  **env = data;
659	
660	    if (environ == env) {
661	
662	        /*
663	         * if the environment is still used, as it happens on exit,
664	         * the only option is to leak it
665	         */
666	
667	        return;
668	    }
669	
670	    ngx_free(env);
