801	static ngx_int_t
802	ngx_get_options(int argc, char *const *argv)
803	{
804	    u_char     *p;
805	    ngx_int_t   i;
806	
807	    for (i = 1; i < argc; i++) {
808	
809	        p = (u_char *) argv[i];
810	
811	        if (*p++ != '-') {
812	            ngx_log_stderr(0, "invalid option: \"%s\"", argv[i]);
813	            return NGX_ERROR;
814	        }
815	
816	        while (*p) {
817	
818	            switch (*p++) {
819	
820	            case '?':
821	            case 'h':
822	                ngx_show_version = 1;
823	                ngx_show_help = 1;
824	                break;
825	
826	            case 'v':
827	                ngx_show_version = 1;
828	                break;
829	
830	            case 'V':
831	                ngx_show_version = 1;
832	                ngx_show_configure = 1;
833	                break;
834	
835	            case 't':
836	                ngx_test_config = 1;
837	                break;
838	
839	            case 'T':
840	                ngx_test_config = 1;
841	                ngx_dump_config = 1;
842	                break;
843	
844	            case 'q':
845	                ngx_quiet_mode = 1;
846	                break;
847	
848	            case 'p':
849	                if (*p) {
850	                    ngx_prefix = p;
851	                    goto next;
852	                }
853	
854	                if (argv[++i]) {
855	                    ngx_prefix = (u_char *) argv[i];
856	                    goto next;
857	                }
858	
859	                ngx_log_stderr(0, "option \"-p\" requires directory name");
860	                return NGX_ERROR;
861	
862	            case 'e':
863	                if (*p) {
864	                    ngx_error_log = p;
865	
866	                } else if (argv[++i]) {
867	                    ngx_error_log = (u_char *) argv[i];
868	
869	                } else {
870	                    ngx_log_stderr(0, "option \"-e\" requires file name");
871	                    return NGX_ERROR;
872	                }
873	
874	                if (ngx_strcmp(ngx_error_log, "stderr") == 0) {
875	                    ngx_error_log = (u_char *) "";
876	                }
877	
878	                goto next;
879	
880	            case 'c':
881	                if (*p) {
882	                    ngx_conf_file = p;
883	                    goto next;
884	                }
885	
886	                if (argv[++i]) {
887	                    ngx_conf_file = (u_char *) argv[i];
888	                    goto next;
889	                }
890	
891	                ngx_log_stderr(0, "option \"-c\" requires file name");
892	                return NGX_ERROR;
893	
894	            case 'g':
895	                if (*p) {
896	                    ngx_conf_params = p;
897	                    goto next;
898	                }
899	
900	                if (argv[++i]) {
901	                    ngx_conf_params = (u_char *) argv[i];
902	                    goto next;
903	                }
904	
905	                ngx_log_stderr(0, "option \"-g\" requires parameter");
906	                return NGX_ERROR;
907	
908	            case 's':
909	                if (*p) {
910	                    ngx_signal = (char *) p;
911	
912	                } else if (argv[++i]) {
913	                    ngx_signal = argv[i];
914	
915	                } else {
916	                    ngx_log_stderr(0, "option \"-s\" requires parameter");
917	                    return NGX_ERROR;
918	                }
919	
920	                if (ngx_strcmp(ngx_signal, "stop") == 0
921	                    || ngx_strcmp(ngx_signal, "quit") == 0
922	                    || ngx_strcmp(ngx_signal, "reopen") == 0
923	                    || ngx_strcmp(ngx_signal, "reload") == 0)
924	                {
925	                    ngx_process = NGX_PROCESS_SIGNALLER;
926	                    goto next;
927	                }
928	
929	                ngx_log_stderr(0, "invalid option: \"-s %s\"", ngx_signal);
930	                return NGX_ERROR;
931	
932	            default:
933	                ngx_log_stderr(0, "invalid option: \"%c\"", *(p - 1));
934	                return NGX_ERROR;
935	            }
936	        }
937	
938	    next:
939	
940	        continue;
941	    }
942	
943	    return NGX_OK;
944	}
