989	static ngx_int_t
990	ngx_process_options(ngx_cycle_t *cycle)
991	{
992	    u_char  *p;
993	    size_t   len;
994	
995	    if (ngx_prefix) {
996	        len = ngx_strlen(ngx_prefix);
997	        p = ngx_prefix;
998	
999	        if (len && !ngx_path_separator(p[len - 1])) {
1000	            p = ngx_pnalloc(cycle->pool, len + 1);
1001	            if (p == NULL) {
1002	                return NGX_ERROR;
1003	            }
1004	
1005	            ngx_memcpy(p, ngx_prefix, len);
1006	            p[len++] = '/';
1007	        }
1008	
1009	        cycle->conf_prefix.len = len;
1010	        cycle->conf_prefix.data = p;
1011	        cycle->prefix.len = len;
1012	        cycle->prefix.data = p;
1013	
1014	    } else {
1015	
1016	#ifndef NGX_PREFIX
1017	
1018	        p = ngx_pnalloc(cycle->pool, NGX_MAX_PATH);
1019	        if (p == NULL) {
1020	            return NGX_ERROR;
1021	        }
1022	
1023	        if (ngx_getcwd(p, NGX_MAX_PATH) == 0) {
1024	            ngx_log_stderr(ngx_errno, "[emerg]: " ngx_getcwd_n " failed");
1025	            return NGX_ERROR;
1026	        }
1027	
1028	        len = ngx_strlen(p);
1029	
1030	        p[len++] = '/';
1031	
1032	        cycle->conf_prefix.len = len;
1033	        cycle->conf_prefix.data = p;
1034	        cycle->prefix.len = len;
1035	        cycle->prefix.data = p;
1036	
1037	#else
1038	
1039	#ifdef NGX_CONF_PREFIX
1040	        ngx_str_set(&cycle->conf_prefix, NGX_CONF_PREFIX);
1041	#else
1042	        ngx_str_set(&cycle->conf_prefix, NGX_PREFIX);
1043	#endif
1044	        ngx_str_set(&cycle->prefix, NGX_PREFIX);
1045	
1046	#endif
1047	    }
1048	
1049	    if (ngx_conf_file) {
1050	        cycle->conf_file.len = ngx_strlen(ngx_conf_file);
1051	        cycle->conf_file.data = ngx_conf_file;
1052	
1053	    } else {
1054	        ngx_str_set(&cycle->conf_file, NGX_CONF_PATH);
1055	    }
1056	
1057	    if (ngx_conf_full_name(cycle, &cycle->conf_file, 0) != NGX_OK) {
1058	        return NGX_ERROR;
1059	    }
1060	
1061	    for (p = cycle->conf_file.data + cycle->conf_file.len - 1;
1062	         p > cycle->conf_file.data;
1063	         p--)
1064	    {
1065	        if (ngx_path_separator(*p)) {
1066	            cycle->conf_prefix.len = p - cycle->conf_file.data + 1;
1067	            cycle->conf_prefix.data = cycle->conf_file.data;
1068	            break;
1069	        }
1070	    }
1071	
1072	    if (ngx_error_log) {
1073	        cycle->error_log.len = ngx_strlen(ngx_error_log);
1074	        cycle->error_log.data = ngx_error_log;
1075	
1076	    } else {
1077	        ngx_str_set(&cycle->error_log, NGX_ERROR_LOG_PATH);
1078	    }
1079	
1080	    if (ngx_conf_params) {
1081	        cycle->conf_param.len = ngx_strlen(ngx_conf_params);
1082	        cycle->conf_param.data = ngx_conf_params;
1083	    }
1084	
1085	    if (ngx_test_config) {
1086	        cycle->log->log_level = NGX_LOG_INFO;
1087	    }
1088	
1089	    return NGX_OK;
1090	}
