1188	    if (ccf->user == (uid_t) NGX_CONF_UNSET_UINT && geteuid() == 0) {
1189	        struct group   *grp;
1190	        struct passwd  *pwd;
1191	
1192	        ngx_set_errno(0);
1193	        pwd = getpwnam(NGX_USER);
1194	        if (pwd == NULL) {
