1202	
1203	        ngx_set_errno(0);
1204	        grp = getgrnam(NGX_GROUP);
1205	        if (grp == NULL) {
1206	            ngx_log_error(NGX_LOG_EMERG, cycle->log, ngx_errno,
1207	                          "getgrnam(\"" NGX_GROUP "\") failed");
1208	            return NGX_CONF_ERROR;
1209	        }
1210	
1211	        ccf->group = grp->gr_gid;
1212	    }
1213	
1214	
1215	    if (ccf->lock_file.len == 0) {
1216	        ngx_str_set(&ccf->lock_file, NGX_LOCK_PATH);
1217	    }
1218	
1219	    if (ngx_conf_full_name(cycle, &ccf->lock_file, 0) != NGX_OK) {
1220	        return NGX_CONF_ERROR;
1221	    }
1222	
1223	    {
1224	    ngx_str_t  lock_file;
1225	
1226	    lock_file = cycle->old_cycle->lock_file;
1227	
1228	    if (lock_file.len) {
1229	        lock_file.len--;
1230	
1231	        if (ccf->lock_file.len != lock_file.len
1232	            || ngx_strncmp(ccf->lock_file.data, lock_file.data, lock_file.len)
1233	               != 0)
1234	        {
1235	            ngx_log_error(NGX_LOG_EMERG, cycle->log, 0,
1236	                          "\"lock_file\" could not be changed, ignored");
1237	        }
1238	
1239	        cycle->lock_file.len = lock_file.len + 1;
1240	        lock_file.len += sizeof(".accept");
1241	
1242	        cycle->lock_file.data = ngx_pstrdup(cycle->pool, &lock_file);
1243	        if (cycle->lock_file.data == NULL) {
1244	            return NGX_CONF_ERROR;
1245	        }
1246	
1247	    } else {
1248	        cycle->lock_file.len = ccf->lock_file.len + 1;
1249	        cycle->lock_file.data = ngx_pnalloc(cycle->pool,
1250	                                      ccf->lock_file.len + sizeof(".accept"));
1251	        if (cycle->lock_file.data == NULL) {
1252	            return NGX_CONF_ERROR;
1253	        }
1254	
1255	        ngx_memcpy(ngx_cpymem(cycle->lock_file.data, ccf->lock_file.data,
1256	                              ccf->lock_file.len),
1257	                   ".accept", sizeof(".accept"));
1258	    }
1259	    }
1260	
1261	#endif
1262	
1263	    return NGX_CONF_OK;
1264	}
