1267	static char *
1268	ngx_set_user(ngx_conf_t *cf, ngx_command_t *cmd, void *conf)
1269	{
1270	#if (NGX_WIN32)
1271	
1272	    ngx_conf_log_error(NGX_LOG_WARN, cf, 0,
1273	                       "\"user\" is not supported, ignored");
1274	
1275	    return NGX_CONF_OK;
1276	
1277	#else
1278	
1279	    ngx_core_conf_t  *ccf = conf;
1280	
1281	    char             *group;
1282	    struct passwd    *pwd;
1283	    struct group     *grp;
1284	    ngx_str_t        *value;
1285	
1286	    if (ccf->user != (uid_t) NGX_CONF_UNSET_UINT) {
1287	        return "is duplicate";
1288	    }
1289	
1290	    if (geteuid() != 0) {
1291	        ngx_conf_log_error(NGX_LOG_WARN, cf, 0,
1292	                           "the \"user\" directive makes sense only "
1293	                           "if the master process runs "
1294	                           "with super-user privileges, ignored");
1295	        return NGX_CONF_OK;
1296	    }
1297	
1298	    value = cf->args->elts;
1299	
1300	    ccf->username = (char *) value[1].data;
1301	
1302	    ngx_set_errno(0);
1303	    pwd = getpwnam((const char *) value[1].data);
1304	    if (pwd == NULL) {
1305	        ngx_conf_log_error(NGX_LOG_EMERG, cf, ngx_errno,
1306	                           "getpwnam(\"%s\") failed", value[1].data);
1307	        return NGX_CONF_ERROR;
1308	    }
1309	
1310	    ccf->user = pwd->pw_uid;
1311	
1312	    group = (char *) ((cf->args->nelts == 2) ? value[1].data : value[2].data);
1313	
1314	    ngx_set_errno(0);
1315	    grp = getgrnam(group);
1316	    if (grp == NULL) {
1317	        ngx_conf_log_error(NGX_LOG_EMERG, cf, ngx_errno,
1318	                           "getgrnam(\"%s\") failed", group);
1319	        return NGX_CONF_ERROR;
1320	    }
1321	
1322	    ccf->group = grp->gr_gid;
1323	
1324	    return NGX_CONF_OK;
1325	
1326	#endif
1327	}
