1329	
1330	static char *
1331	ngx_set_env(ngx_conf_t *cf, ngx_command_t *cmd, void *conf)
1332	{
1333	    ngx_core_conf_t  *ccf = conf;
1334	
1335	    ngx_str_t   *value, *var;
1336	    ngx_uint_t   i;
1337	
1338	    var = ngx_array_push(&ccf->env);
1339	    if (var == NULL) {
1340	        return NGX_CONF_ERROR;
1341	    }
1342	
1343	    value = cf->args->elts;
1344	    *var = value[1];
1345	
1346	    for (i = 0; i < value[1].len; i++) {
1347	
1348	        if (value[1].data[i] == '=') {
1349	
1350	            var->len = i;
1351	
1352	            return NGX_CONF_OK;
1353	        }
1354	    }
1355	
1356	    return NGX_CONF_OK;
1357	}
