1361	ngx_set_priority(ngx_conf_t *cf, ngx_command_t *cmd, void *conf)
1362	{
1363	    ngx_core_conf_t  *ccf = conf;
1364	
1365	    ngx_str_t        *value;
1366	    ngx_uint_t        n, minus;
1367	
1368	    if (ccf->priority != 0) {
1369	        return "is duplicate";
1370	    }
1371	
1372	    value = cf->args->elts;
1373	
1374	    if (value[1].data[0] == '-') {
1375	        n = 1;
1376	        minus = 1;
1377	
1378	    } else if (value[1].data[0] == '+') {
1379	        n = 1;
1380	        minus = 0;
1381	
1382	    } else {
1383	        n = 0;
1384	        minus = 0;
1385	    }
1386	
1387	    ccf->priority = ngx_atoi(&value[1].data[n], value[1].len - n);
1388	    if (ccf->priority == NGX_ERROR) {
1389	        return "invalid number";
1390	    }
1391	
1392	    if (minus) {
1393	        ccf->priority = -ccf->priority;
1394	    }
1395	
1396	    return NGX_CONF_OK;
1397	}
