1400	static char *
1401	ngx_set_cpu_affinity(ngx_conf_t *cf, ngx_command_t *cmd, void *conf)
1402	{
1403	#if (NGX_HAVE_CPU_AFFINITY)
1404	    ngx_core_conf_t  *ccf = conf;
1405	
1406	    u_char            ch, *p;
1407	    ngx_str_t        *value;
1408	    ngx_uint_t        i, n;
1409	    ngx_cpuset_t     *mask;
1410	
1411	    if (ccf->cpu_affinity) {
1412	        return "is duplicate";
1413	    }
1414	
1415	    mask = ngx_palloc(cf->pool, (cf->args->nelts - 1) * sizeof(ngx_cpuset_t));
1416	    if (mask == NULL) {
1417	        return NGX_CONF_ERROR;
1418	    }
1419	
1420	    ccf->cpu_affinity_n = cf->args->nelts - 1;
1421	    ccf->cpu_affinity = mask;
1422	
1423	    value = cf->args->elts;
1424	
1425	    if (ngx_strcmp(value[1].data, "auto") == 0) {
1426	
1427	        if (cf->args->nelts > 3) {
1428	            ngx_conf_log_error(NGX_LOG_EMERG, cf, 0,
1429	                               "invalid number of arguments in "
1430	                               "\"worker_cpu_affinity\" directive");
1431	            return NGX_CONF_ERROR;
1432	        }
1433	
1434	        ccf->cpu_affinity_auto = 1;
1435	
1436	        CPU_ZERO(&mask[0]);
1437	        for (i = 0; i < (ngx_uint_t) ngx_min(ngx_ncpu, CPU_SETSIZE); i++) {
1438	            CPU_SET(i, &mask[0]);
1439	        }
1440	
1441	        n = 2;
1442	
1443	    } else {
1444	        n = 1;
1445	    }
1446	
1447	    for ( /* void */ ; n < cf->args->nelts; n++) {
1448	
1449	        if (value[n].len > CPU_SETSIZE) {
1450	            ngx_conf_log_error(NGX_LOG_EMERG, cf, 0,
1451	                         "\"worker_cpu_affinity\" supports up to %d CPUs only",
1452	                         CPU_SETSIZE);
1453	            return NGX_CONF_ERROR;
1454	        }
1455	
1456	        i = 0;
1457	        CPU_ZERO(&mask[n - 1]);
1458	
1459	        for (p = value[n].data + value[n].len - 1;
1460	             p >= value[n].data;
1461	             p--)
1462	        {
1463	            ch = *p;
1464	
1465	            if (ch == ' ') {
1466	                continue;
1467	            }
1468	
1469	            i++;
1470	
1471	            if (ch == '0') {
1472	                continue;
1473	            }
1474	
1475	            if (ch == '1') {
1476	                CPU_SET(i - 1, &mask[n - 1]);
1477	                continue;
1478	            }
1479	
1480	            ngx_conf_log_error(NGX_LOG_EMERG, cf, 0,
1481	                          "invalid character \"%c\" in \"worker_cpu_affinity\"",
1482	                          ch);
1483	            return NGX_CONF_ERROR;
1484	        }
1485	    }
1486	
1487	#else
1488	
1489	    ngx_conf_log_error(NGX_LOG_WARN, cf, 0,
1490	                       "\"worker_cpu_affinity\" is not supported "
1491	                       "on this platform, ignored");
1492	#endif
1493	
1494	    return NGX_CONF_OK;
1495	}
1496	
1497	
1498	ngx_cpuset_t *
1499	ngx_get_cpu_affinity(ngx_uint_t n)
1500	{
1501	#if (NGX_HAVE_CPU_AFFINITY)
1502	    ngx_uint_t        i, j;
1503	    ngx_cpuset_t     *mask;
1504	    ngx_core_conf_t  *ccf;
1505	
1506	    static ngx_cpuset_t  result;
1507	
1508	    ccf = (ngx_core_conf_t *) ngx_get_conf(ngx_cycle->conf_ctx,
1509	                                           ngx_core_module);
1510	
1511	    if (ccf->cpu_affinity == NULL) {
1512	        return NULL;
1513	    }
1514	
1515	    if (ccf->cpu_affinity_auto) {
1516	        mask = &ccf->cpu_affinity[ccf->cpu_affinity_n - 1];
1517	
1518	        for (i = 0, j = n; /* void */ ; i++) {
1519	
1520	            if (CPU_ISSET(i % CPU_SETSIZE, mask) && j-- == 0) {
1521	                break;
1522	            }
1523	
1524	            if (i == CPU_SETSIZE && j == n) {
1525	                /* empty mask */
1526	                return NULL;
1527	            }
1528	
1529	            /* void */
1530	        }
1531	
1532	        CPU_ZERO(&result);
1533	        CPU_SET(i % CPU_SETSIZE, &result);
1534	
1535	        return &result;
1536	    }
1537	
1538	    if (ccf->cpu_affinity_n > n) {
1539	        return &ccf->cpu_affinity[n];
1540	    }
1541	
1542	    return &ccf->cpu_affinity[ccf->cpu_affinity_n - 1];
1543	
1544	#else
1545	
1546	    return NULL;
1547	
1548	#endif
1549	}
