1581	static char *
1582	ngx_load_module(ngx_conf_t *cf, ngx_command_t *cmd, void *conf)
1583	{
1584	#if (NGX_HAVE_DLOPEN)
1585	    void                *handle;
1586	    char               **names, **order;
1587	    ngx_str_t           *value, file;
1588	    ngx_uint_t           i;
1589	    ngx_module_t        *module, **modules;
1590	    ngx_pool_cleanup_t  *cln;
1591	
1592	    if (cf->cycle->modules_used) {
1593	        return "is specified too late";
1594	    }
1595	
1596	    value = cf->args->elts;
1597	
1598	    file = value[1];
1599	
1600	    if (ngx_conf_full_name(cf->cycle, &file, 0) != NGX_OK) {
1601	        return NGX_CONF_ERROR;
1602	    }
1603	
1604	    cln = ngx_pool_cleanup_add(cf->cycle->pool, 0);
1605	    if (cln == NULL) {
1606	        return NGX_CONF_ERROR;
1607	    }
1608	
1609	    handle = ngx_dlopen(file.data);
1610	    if (handle == NULL) {
1611	        ngx_conf_log_error(NGX_LOG_EMERG, cf, 0,
1612	                           ngx_dlopen_n " \"%s\" failed (%s)",
1613	                           file.data, ngx_dlerror());
1614	        return NGX_CONF_ERROR;
1615	    }
1616	
1617	    cln->handler = ngx_unload_module;
1618	    cln->data = handle;
1619	
1620	    modules = ngx_dlsym(handle, "ngx_modules");
1621	    if (modules == NULL) {
1622	        ngx_conf_log_error(NGX_LOG_EMERG, cf, 0,
1623	                           ngx_dlsym_n " \"%V\", \"%s\" failed (%s)",
1624	                           &value[1], "ngx_modules", ngx_dlerror());
1625	        return NGX_CONF_ERROR;
1626	    }
1627	
1628	    names = ngx_dlsym(handle, "ngx_module_names");
1629	    if (names == NULL) {
1630	        ngx_conf_log_error(NGX_LOG_EMERG, cf, 0,
1631	                           ngx_dlsym_n " \"%V\", \"%s\" failed (%s)",
1632	                           &value[1], "ngx_module_names", ngx_dlerror());
1633	        return NGX_CONF_ERROR;
1634	    }
1635	
1636	    order = ngx_dlsym(handle, "ngx_module_order");
1637	
1638	    for (i = 0; modules[i]; i++) {
1639	        module = modules[i];
1640	        module->name = names[i];
1641	
1642	        if (ngx_add_module(cf, &file, module, order) != NGX_OK) {
1643	            return NGX_CONF_ERROR;
1644	        }
1645	
1646	        ngx_log_debug2(NGX_LOG_DEBUG_CORE, cf->log, 0, "module: %s i:%ui",
1647	                       module->name, module->index);
1648	    }
1649	
1650	    return NGX_CONF_OK;
1651	
1652	#else
1653	
1654	    ngx_conf_log_error(NGX_LOG_EMERG, cf, 0,
1655	                       "\"load_module\" is not supported "
1656	                       "on this platform");
1657	    return NGX_CONF_ERROR;
1658	
1659	#endif
1660	}
1661	
